+		registry = make(map[AgentName]Factory)
+		registryMu.Unlock()
+
+		Register(AgentName("agent-x"), func() Agent {
+			return &protectedDirAgent{dirs: []string{".shared"}}
+		})
+		Register(AgentName("agent-y"), func() Agent {
+			return &protectedDirAgent{dirs: []string{".shared"}}
+		})
+
+		dirs := AllProtectedDirs()
